     8→} from '../db/sessions.js';
     9→import { getContainerById } from '../db/containers.js';
    10→import { createFeedEntry, getFeedEntriesBySessionId } from '../db/feed-entries.js';
    11→import type { Session, SessionType } from '../../types/session.js';
    12→import type { FeedEntry, FeedRole } from '../../types/feed.js';
    13→import { emitFeedEntry } from './feed-emitter.js';
    14→
    15→export interface CreateSessionInput {
    16→	name: string;
    17→	type: SessionType;
    18→	containerId: string;
    19→}
    20→
    21→export interface SessionDetail {
    22→	session: Session;
    23→	feedEntries: FeedEntry[];
    24→}
    25→
    26→function generateId(): string {
    27→	return randomUUID().replace(/-/g, '');
    28→}
    29→
    30→function toSession(row: {
    31→	id: string;
    32→	name: string;
    33→	type: string;
    34→	container_id: string;
    35→	status: string;
    36→	created_at: string;
    37→	updated_at: string;
    38→}): Session {
    39→	return {
    40→		id: row.id,
    41→		name: row.name,
    42→		type: row.type as SessionType,
    43→		containerId: row.container_id,
    44→		status: row.status as Session['status'],
    45→		createdAt: row.created_at,
    46→		updatedAt: row.updated_at
    47→	};
    48→}
    49→
    50→function toFeedEntry(row: {
    51→	id: string;
    52→	session_id: string;
    53→	role: string;
    54→	content: string;
    55→	metadata: Record<string, unknown>;
    56→	created_at: string;
    57→}): FeedEntry {
    58→	return {
    59→		id: row.id,
    60→		sessionId: row.session_id,
    61→		role: row.role as FeedRole,
    62→		content: row.content,
    63→		metadata: row.metadata as FeedEntry['metadata'],
    64→		ts: row.created_at
    65→	};
    66→}
    67→
    68→export class SessionService {
    69→	constructor(private db: Database.Database) {}
    70→
    71→	async create(input: CreateSessionInput): Promise<Session> {
    72→		const container = getContainerById(this.db, input.containerId);
    73→		if (!container) {
    74→			throw new Error(`Container '${input.containerId}' not found`);
    75→		}
    76→
    77→		const row = dbCreate(this.db, {
    78→			id: generateId(),
    79→			name: input.name,
    80→			type: input.type,
    81→			container_id: input.containerId,
    82→			status: 'idle'
    83→		});
    84→		return toSession(row);
    85→	}
    86→
    87→	async list(containerId?: string): Promise<Session[]> {
    88→		return getAllSessions(this.db, containerId).map(toSession);
    89→	}
    90→
    91→	async get(id: string): Promise<SessionDetail | null> {
    92→		const row = getSessionById(this.db, id);
    93→		if (!row) return null;
    94→
    95→		const feedRows = getFeedEntriesBySessionId(this.db, id);
    96→		return {
    97→			session: toSession(row),
    98→			feedEntries: feedRows.map(toFeedEntry)
    99→		};
   100→	}
   101→
   102→	async addInput(id: string, content: string): Promise<FeedEntry> {
   103→		const row = getSessionById(this.db, id);
   104→		if (!row) {
   105→			throw new Error(`Session '${id}' not found`);
   106→		}
   107→
   108→		const entryRow = createFeedEntry(this.db, {
   109→			id: generateId(),
   110→			session_id: id,
   111→			role: 'human',
   112→			content
   113→		});
   114→		const entry = toFeedEntry(entryRow);
   115→		emitFeedEntry(id, entry);
   116→		return entry;
   117→	}
   118→
   119→	async end(id: string): Promise<void> {
   120→		const row = getSessionById(this.db, id);
   121→		if (!row) {
   122→			throw new Error(`Session '${id}' not found`);
   123→		}
   124→		dbDelete(this.db, id);
   125→	}
   126→}
