     6→
     7→export async function _handleGetStream(id: string, service: SessionService): Promise<Response> {
     8→	const detail = await service.get(id);
     9→	if (!detail) {
    10→		return errorResponse(`Session '${id}' not found`, 404);
    11→	}
    12→
    13→	const encoder = new TextEncoder();
    14→	let unsubscribe: (() => void) | null = null;
    15→
    16→	const stream = new ReadableStream<Uint8Array>({
    17→		start(controller): void {
    18→			unsubscribe = subscribeFeedEntry(id, (entry: FeedEntry): void => {
    19→				const data = `data: ${JSON.stringify(entry)}\n\n`;
    20→				controller.enqueue(encoder.encode(data));
    21→			});
    22→		},
    23→		cancel(): void {
    24→			unsubscribe?.();
    25→		}
    26→	});
    27→
    28→	return new Response(stream, {
    29→		status: 200,
    30→		headers: {
    31→			'Content-Type': 'text/event-stream',
    32→			'Cache-Control': 'no-cache',
    33→			Connection: 'keep-alive'
    34→		}
    35→	});
    36→}
    37→
    38→export const GET: RequestHandler = async ({ params }) => {
    39→	const { getSessionService } = await import('$lib/server/sessions/singleton.js');
    40→	return _handleGetStream(params.id, getSessionService());
    41→};
