     1→import { EventEmitter } from 'events';
     2→import type { FeedEntry } from '$lib/types/feed.js';
     3→
     4→const emitter = new EventEmitter();
     5→emitter.setMaxListeners(200);
     6→
     7→function eventKey(sessionId: string): string {
     8→	return `feed:${sessionId}`;
     9→}
    10→
    11→export function emitFeedEntry(sessionId: string, entry: FeedEntry): void {
    12→	emitter.emit(eventKey(sessionId), entry);
    13→}
    14→
    15→export function subscribeFeedEntry(
    16→	sessionId: string,
    17→	handler: (entry: FeedEntry) => void
    18→): () => void {
    19→	const key = eventKey(sessionId);
    20→	emitter.on(key, handler);
    21→	let removed = false;
    22→	return () => {
    23→		if (!removed) {
    24→			removed = true;
    25→			emitter.off(key, handler);
    26→		}
    27→	};
    28→}
